request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId ?normId WHERE {
  ?org tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }

  FILTER(
    EXISTS {
      ?model bbo:name ?mName .
      FILTER(CONTAINS(LCASE(STR(?mName)), "transport") || CONTAINS(LCASE(STR(?mName)), "organs") || CONTAINS(LCASE(STR(?mName)), "organ"))
    }
    || EXISTS {
      ?model tai:description ?d .
      FILTER(CONTAINS(LCASE(STR(?d)), "transport") || CONTAINS(LCASE(STR(?d)), "organs") || CONTAINS(LCASE(STR(?d)), "organ"))
    }
  )
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?origId ?normId ?modelDesc WHERE {
  ?org tai:organizationId "38b17e822a5e4307ae051694293e4d0f" .
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:description ?modelDesc . }

  FILTER(
    ( !BOUND(?modelName) || (CONTAINS(LCASE(STR(?modelName)), "organ") ) )
    || ( !BOUND(?modelDesc) || (CONTAINS(LCASE(STR(?modelDesc)), "organ") ) )
    || CONTAINS(LCASE(STR(?modelDesc)), "transport")
    || CONTAINS(LCASE(STR(?modelName)), "transport")
  )
}
ORDER BY DESC(?created)
LIMIT 25
